package il.co.dcd.composermapper.service; import il.co.dcd.composermapper.model.DiscoveredFile; import java.nio.file.*; import java.io.IOException; import java.util.*;
public class FileDiscoveryService { public List<DiscoveredFile> discover(Path root){ List<DiscoveredFile> out=new ArrayList<>(); try(var s=Files.walk(root)){ s.filter(Files::isRegularFile).forEach(p->{ String l=p.getFileName().toString().toLowerCase(); if(l.endsWith(".xml")) out.add(new DiscoveredFile(p,DiscoveredFile.FileType.XML)); else if(l.endsWith(".ini")) out.add(new DiscoveredFile(p,DiscoveredFile.FileType.INI)); else if(l.endsWith(".java")) out.add(new DiscoveredFile(p,DiscoveredFile.FileType.JAVA)); }); }catch(IOException e){ throw new RuntimeException("Failed scanning: "+root,e);} return out; } }
